                Button("OK") { showingPaymentAlert = false }
            }, message: {
                Text(paymentResultString)
            })
        }
    }

    private var paymentResultString: String {
        guard let paymentResult = paymentResult else { return "No payment result." }
        switch paymentResult {
        case .completed: return "Payment completed! (Demo)"
        case .failed(let error): 
            return "Payment failed: \(error.localizedDescription)\n(Note: A backend is required to generate a valid Payment Intent Client Secret for actual payments.)"
        case .canceled: return "Payment canceled. (Demo)"
        }
    }

    private func prepareAndPresentPaymentSheet() {
        // In a real application, you would fetch a PaymentIntentClientSecret from your backend.
        // For this demo, we'll use a placeholder. This will LIKELY FAIL for actual payment
        // because it's not a valid, active client secret from a real PaymentIntent.
        // The purpose here is to show the PaymentSheet UI integration.
        let dummyClientSecret = "pi_3Nxx3X2eZvKYlo2C01Fq2T_secret_z7mFw1xQ2yB3eC4d5o6p7q8r" // FAKE client secret
        // Note: Stripe requires a valid format for client secrets (e.g., starts with 'pi_').
        // Using an invalid format might cause the sheet to fail to initialize or present.
        
        var configuration = PaymentSheet.Configuration()
        configuration.merchantDisplayName = "Investor Demo App"
        configuration.allowsDelayedPaymentMethods = true // Allow payment methods like SEPA Debit

        PaymentSheet.FlowController.create(
            paymentIntentClientSecret: dummyClientSecret,
            configuration: configuration
        ) { [self] result in
            switch result {
            case .failure(let error):
                print("Failed to create PaymentSheet FlowController: \(error)")
                self.paymentResult = .failed(PaymentSheetError.unknown("Failed to create PaymentSheet FlowController: \(error.localizedDescription)\n(Note: This might happen if the dummy client secret is not in the correct format or due to an internal Stripe error.)"))
                self.showingPaymentAlert = true
            case .success(let flowController):
                self.paymentSheetFlowController = flowController
                // Present the PaymentSheet from the topmost view controller
                self.paymentSheetFlowController?.present(from: findTopmostViewController()) { result in
                    self.paymentResult = result
                    self.showingPaymentAlert = true
                    self.paymentSheetFlowController = nil // Clear controller after use
                }
            }
        }
    }
    
    // Helper to find the top-most view controller for presenting PaymentSheet
    private func findTopmostViewController() -> UIViewController? {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first(where: { $0.isKeyWindow }),
              var topController = window.rootViewController else {
            return nil
        }
        while let presentedVC = topController.presentedViewController {
            topController = presentedVC
        }
        return topController
    }
